  private rotateRight(y: AVLNode<K, V>): AVLNode<K, V> {
    const x = y.left!;
    const B = x.right;
    x.right = y;
    y.left = B;
    this.updateHeight(y);
    this.updateHeight(x);
    return x;
  }

