   * Left rotation around x.
   *
   *     x                  y
   *    / \                / \
   *   A   y    →        x   C
   *      / \           / \
   *     B   C         A   B
   */
  private rotateLeft(x: AVLNode<K, V>): AVLNode<K, V> {
    const y = x.right!;
    const B = y.left;
    y.left = x;
    x.right = B;
    this.updateHeight(x);
    this.updateHeight(y);
    return y;
  }

